export const FormatOperator = {
  equals: 'equals',
  notEquals: 'notEquals',
  contains: 'contains',
  notContains: 'notContains',
  empty: 'empty',
  notEmpty: 'notEmpty',
  gt: 'gt',
  lt: 'lt',
  gte: 'gte',
  lte: 'lte',
} as const;

/**
 * One conditional-formatting rule. When a cell value matches operator/value, the cell is painted cellColor and/or the row rowColor, and the cell text is painted textColor. Rules are evaluated in order; first match wins per field.
 */
export interface FieldFormatRule {
  operator: FormatOperator;
  value?: string;
  cellColor?: string;
  rowColor?: string;
  textColor?: string;
}

export type ValidationOperator = typeof ValidationOperator[keyof typeof ValidationOperator];


export const ValidationOperator = {
  empty: 'empty',
  notEmpty: 'notEmpty',
  equals: 'equals',
  notEquals: 'notEquals',
  gt: 'gt',
  lt: 'lt',
  gte: 'gte',
  lte: 'lte',
  between: 'between',
} as const;

/**
 * One cross-field validation ("fill") rule. Distinct from conditional formatting (which is cosmetic): this is a HARD constraint on saving. Saving THIS field with a value (any non-empty value, or one of applyToValues when that list is non-empty) is allowed only when the field named conditionFieldKey (same entity) satisfies operator/value (value2 is the upper bound for `between`). Otherwise the record save is rejected server-side with an auto-generated message.
 */
export interface FieldValidationRule {
  /** When non-empty, the rule applies only if THIS field's new value is one of these. Empty/absent = applies to any non-empty value. */
  applyToValues?: string[];
  conditionFieldKey: string;
  operator: ValidationOperator;
  value?: string;
  value2?: string;
}

/**
 * Per-field configuration for a `function`-type field. `expression` is a safe formula referencing other fields of the same record via {field_key}; it is computed at read time and never stored. `decimals`, when set, rounds a numeric result to that many decimal places on display.
 */
export interface FormulaFieldConfig {
  expression?: string;
  /**
     * Optional. When set and the formula result is numeric, the value is rounded and shown with this many decimal places. Null/omitted means no rounding. Ignored for non-numeric (text/boolean) results.
     * @minimum 0
     * @maximum 10
     */
  decimals?: number | null;
}

/**
 * Per-field configuration for a dependent ("cascading") field. When `dependsOnFieldKey` is set, this field is gated on the parent field: its picker is disabled until the parent has a value. For a `text` field, its option list is the distinct existing values of this field among records whose parent-chain matches the current row. For a `relation` field, `relatedFilterFieldKey` names a field on the RELATED entity; the candidate list is narrowed to related records whose that field matches the parent field's value in the row being edited.
 */
export interface DependencyFieldConfig {
  dependsOnFieldKey?: string;
  /** Relation fields only. The field key on the related entity whose value must match the parent field's value for a record to be offered as a link candidate. */
  relatedFilterFieldKey?: string;
}

